package org.example.travel360.controller;

import org.example.travel360.dto.BookingDTO;
import org.example.travel360.dto.ItineraryDTO;
import org.example.travel360.dto.ReservationDTO;
import org.example.travel360.service.ItineraryService;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

/**
 * REST Controller for Itinerary API
 * Exposes endpoints using DTOs for data transfer
 *
 * API Benefits:
 * - Decouples frontend from database entity structure
 * - Allows selective field exposure (security & simplicity)
 * - Makes versioning APIs easier
 * - Improves code maintainability
 */
@RestController
@RequestMapping("/api/itinerary")
@CrossOrigin(origins = "*", maxAge = 3600)
public class ItineraryRestController {

    private final ItineraryService itineraryService;

    public ItineraryRestController(ItineraryService itineraryService) {
        this.itineraryService = itineraryService;
    }

    /**
     * Generate itinerary for a specific user
     * POST /api/itinerary/generate/{userId}
     *
     * @param userId The user ID
     * @return ResponseEntity with ItineraryDTO
     */
    @PostMapping("/generate/{userId}")
    public ResponseEntity<?> generateItinerary(@PathVariable Integer userId) {
        try {
            ItineraryDTO itineraryDTO = itineraryService.generateItinerary(userId);
            if (itineraryDTO == null) {
                return ResponseEntity.status(HttpStatus.NOT_FOUND)
                        .body("Unable to generate itinerary for user: " + userId);
            }
            return ResponseEntity.status(HttpStatus.CREATED).body(itineraryDTO);
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body("Error generating itinerary: " + e.getMessage());
        }
    }

    /**
     * Retrieve itinerary by ID
     * GET /api/itinerary/{itineraryId}
     *
     * @param itineraryId The itinerary ID
     * @return ResponseEntity with ItineraryDTO
     */
    @GetMapping("/{itineraryId}")
    public ResponseEntity<?> getItinerary(@PathVariable Integer itineraryId) {
        try {
            ItineraryDTO itineraryDTO = itineraryService.getItineraryById(itineraryId);
            if (itineraryDTO == null) {
                return ResponseEntity.status(HttpStatus.NOT_FOUND)
                        .body("Itinerary not found with ID: " + itineraryId);
            }
            return ResponseEntity.ok(itineraryDTO);
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body("Error retrieving itinerary: " + e.getMessage());
        }
    }

    /**
     * Retrieve booking by user ID
     * GET /api/itinerary/booking/{userId}
     *
     * @param userId The user ID
     * @return ResponseEntity with BookingDTO
     */
    @GetMapping("/booking/{userId}")
    public ResponseEntity<?> getBookingByUserId(@PathVariable Integer userId) {
        try {
            BookingDTO bookingDTO = itineraryService.getBookingByUserId(userId);
            if (bookingDTO == null) {
                return ResponseEntity.status(HttpStatus.NOT_FOUND)
                        .body("Booking not found for user: " + userId);
            }
            return ResponseEntity.ok(bookingDTO);
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body("Error retrieving booking: " + e.getMessage());
        }
    }

    /**
     * Retrieve reservation by booking ID
     * GET /api/itinerary/reservation/{bookingId}
     *
     * @param bookingId The booking ID
     * @return ResponseEntity with ReservationDTO
     */
    @GetMapping("/reservation/{bookingId}")
    public ResponseEntity<?> getReservationByBookingId(@PathVariable Integer bookingId) {
        try {
            ReservationDTO reservationDTO = itineraryService.getReservationByBookingId(bookingId);
            if (reservationDTO == null) {
                return ResponseEntity.status(HttpStatus.NOT_FOUND)
                        .body("Reservation not found for booking: " + bookingId);
            }
            return ResponseEntity.ok(reservationDTO);
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body("Error retrieving reservation: " + e.getMessage());
        }
    }

    /**
     * Health check endpoint
     * GET /api/itinerary/health
     *
     * @return Simple string response
     */
    @GetMapping("/health")
    public ResponseEntity<String> health() {
        return ResponseEntity.ok("Itinerary API is running!");
    }
}

